import { forwardRef, type InputHTMLAttributes, type ReactNode } from "react";
import { cn } from "../../lib/utils.js";

export interface InputProps extends InputHTMLAttributes<HTMLInputElement> {
  /** Label text rendered above the input. */
  label?: string;
  /** Error message shown below the input. */
  error?: string | undefined;
  /** Optional data-testid for the error message element. */
  errorTestId?: string;
  /** Optional icon or element rendered inside the input (left side). */
  icon?: ReactNode;
}

const Input = forwardRef<HTMLInputElement, InputProps>(
  ({ className, label, error, errorTestId, icon, id, ...props }, ref) => {
    const inputId = id ?? (label ? `input-${label.toLowerCase().replace(/\s+/g, "-")}` : undefined);

    return (
      <div className="flex flex-col gap-1.5">
        {label && (
          <label
            htmlFor={inputId}
            className="text-sm font-medium text-foreground"
          >
            {label}
          </label>
        )}
        <div className="relative">
          {icon && (
            <span className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 text-muted">
              {icon}
            </span>
          )}
          <input
            ref={ref}
            id={inputId}
            className={cn(
              "flex h-9 w-full rounded-default border border-border bg-surface px-3 py-1.5 text-sm text-foreground",
              "placeholder:text-muted/60",
              "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50 focus-visible:border-primary",
              "disabled:cursor-not-allowed disabled:opacity-50",
              icon && "pl-9",
              error && "border-danger focus-visible:ring-danger/50",
              className,
            )}
            aria-invalid={error ? true : undefined}
            aria-describedby={error && inputId ? `${inputId}-error` : undefined}
            {...props}
          />
        </div>
        {error && (
          <p
            id={inputId ? `${inputId}-error` : undefined}
            data-testid={errorTestId}
            className="text-xs text-danger"
            role="alert"
          >
            {error}
          </p>
        )}
      </div>
    );
  },
);
Input.displayName = "Input";

export { Input };

/**
 * Toast notification system.
 * Can be driven by the HostBridge NotificationBridge or used standalone.
 */
import { useState, useCallback, createContext, useContext, type ReactNode } from "react";
import { cva } from "class-variance-authority";
import { cn } from "../../lib/utils.js";
import { X } from "lucide-react";

/* ── Toast Variant Styles ──────────────────────────────────────────── */

const toastVariants = cva(
  "pointer-events-auto flex items-center gap-3 rounded-default border px-4 py-3 text-sm shadow-lg transition-all",
  {
    variants: {
      type: {
        success: "border-success/30 bg-success/10 text-success",
        info: "border-primary/30 bg-primary/10 text-primary",
        warning: "border-warning/30 bg-warning/10 text-warning",
        error: "border-danger/30 bg-danger/10 text-danger",
      },
    },
    defaultVariants: { type: "info" },
  },
);

/* ── Types ─────────────────────────────────────────────────────────── */

interface ToastItem {
  id: string;
  type: "success" | "info" | "warning" | "error";
  message: string;
}

interface ToastContextValue {
  showToast(options: {
    type: "success" | "info" | "warning" | "error";
    message: string;
    durationMs?: number;
  }): void;
}

/* ── Context ───────────────────────────────────────────────────────── */

const ToastContext = createContext<ToastContextValue | null>(null);

function useToast(): ToastContextValue {
  const ctx = useContext(ToastContext);
  if (!ctx) throw new Error("useToast must be used within <ToastProvider>");
  return ctx;
}

/* ── Provider ──────────────────────────────────────────────────────── */

let toastCounter = 0;

function ToastProvider({ children }: { children: ReactNode }) {
  const [toasts, setToasts] = useState<ToastItem[]>([]);

  const showToast = useCallback(
    (options: {
      type: "success" | "info" | "warning" | "error";
      message: string;
      durationMs?: number;
    }) => {
      const id = `toast-${++toastCounter}`;
      setToasts((prev) => [...prev, { id, type: options.type, message: options.message }]);
      setTimeout(() => {
        setToasts((prev) => prev.filter((t) => t.id !== id));
      }, options.durationMs ?? 4000);
    },
    [],
  );

  const dismiss = useCallback((id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  }, []);

  return (
    <ToastContext.Provider value={{ showToast }}>
      {children}
      {/* Toast container */}
      <div
        aria-live="polite"
        className="pointer-events-none fixed bottom-4 right-4 z-[100] flex flex-col gap-2"
      >
        {toasts.map((t) => (
          <div key={t.id} className={cn(toastVariants({ type: t.type }))}>
            <span className="flex-1">{t.message}</span>
            <button
              type="button"
              onClick={() => dismiss(t.id)}
              className="pointer-events-auto rounded-sm p-0.5 opacity-70 hover:opacity-100"
              aria-label="Dismiss"
            >
              <X className="h-3.5 w-3.5" />
            </button>
          </div>
        ))}
      </div>
    </ToastContext.Provider>
  );
}

export { ToastProvider, useToast, toastVariants };

/**
 * App shell — polished sidebar + header + content layout.
 * Applies design tokens as CSS custom properties on the root element.
 * Sidebar is collapsible with state persisted to localStorage.
 */
import { type ReactNode, useState, useEffect } from "react";
import type { DesignTokens } from "@weekly-commit/shared";
import { useHostBridge } from "../host/HostProvider.js";
import { Navigation } from "./Navigation.js";
import { Header, getWeekMonday } from "./Header.js";
import { cn } from "../lib/utils.js";
import { useTheme } from "../lib/useTheme.js";

interface AppShellProps {
  readonly children: ReactNode;
}

const SIDEBAR_KEY = "wc-sidebar-collapsed";

/**
 * Converts DesignTokens into CSS custom properties.
 *
 * When dark mode is active, color tokens are omitted so the CSS
 * [data-theme="dark"] overrides in index.css take effect. Non-color
 * tokens (font, spacing, radius) always apply.
 */
function tokensToStyle(
  tokens: DesignTokens,
  isDark: boolean,
): React.CSSProperties {
  const base: Record<string, string> = {
    "--font-family-base": tokens.fontFamilyBase,
    "--font-size-base": tokens.fontSizeBase,
    "--border-radius": tokens.borderRadius,
    "--spacing-unit": tokens.spacingUnit,
  };

  if (!isDark) {
    // In light mode (or host-provided), apply color tokens as inline vars
    // so the host app's palette overrides our CSS defaults.
    Object.assign(base, {
      "--color-primary": tokens.colorPrimary,
      "--color-secondary": tokens.colorSecondary,
      "--color-background": tokens.colorBackground,
      "--color-surface": tokens.colorSurface,
      "--color-text": tokens.colorText,
      "--color-text-muted": tokens.colorTextMuted,
      "--color-border": tokens.colorBorder,
      "--color-success": tokens.colorSuccess,
      "--color-warning": tokens.colorWarning,
      "--color-danger": tokens.colorDanger,
    });
  }

  return base as React.CSSProperties;
}

export function AppShell({ children }: AppShellProps) {
  const { tokens } = useHostBridge();
  const { resolved } = useTheme();
  const isDark = resolved === "dark";
  const [selectedWeek, setSelectedWeek] = useState(() =>
    getWeekMonday(new Date()),
  );
  const [collapsed, setCollapsed] = useState(() => {
    try {
      return localStorage.getItem(SIDEBAR_KEY) === "true";
    } catch {
      return false;
    }
  });

  useEffect(() => {
    try {
      localStorage.setItem(SIDEBAR_KEY, String(collapsed));
    } catch {
      // ignore
    }
  }, [collapsed]);

  return (
    <div
      className="flex h-screen flex-col overflow-hidden bg-background text-foreground"
      style={{
        ...tokensToStyle(tokens, isDark),
        fontFamily: "var(--font-family-base)",
        fontSize: "var(--font-size-base)",
      }}
      data-testid="app-shell"
    >
      {/* Header */}
      <Header
        selectedWeek={selectedWeek}
        onWeekChange={setSelectedWeek}
        collapsed={collapsed}
        onToggleSidebar={() => setCollapsed((c) => !c)}
      />

      {/* Body: sidebar + main */}
      <div className="flex flex-1 overflow-hidden">
        {/* Sidebar */}
        <aside
          className={cn(
            "flex shrink-0 flex-col border-r border-border bg-surface transition-sidebar overflow-y-auto overflow-x-hidden",
            collapsed ? "w-14 px-1.5 py-4" : "w-56 px-3 py-4",
          )}
          aria-label="Sidebar"
        >
          {/* Brand mark in sidebar — visible when expanded */}
          {!collapsed && (
            <div className="mb-6 px-3">
              <p className="text-[10px] font-semibold uppercase tracking-widest text-muted">
                Navigation
              </p>
            </div>
          )}

          <Navigation collapsed={collapsed} />

          {/* Spacer pushes bottom content down */}
          <div className="flex-1" />

          {/* Version or help link at bottom */}
          {!collapsed && (
            <div className="mt-4 px-3 pt-4 border-t border-border">
              <p className="text-[10px] text-muted">v1.0.0</p>
            </div>
          )}
        </aside>

        {/* Main content */}
        <main
          className="flex-1 overflow-auto p-6"
          role="main"
        >
          {children}
        </main>
      </div>
    </div>
  );
}

import {
  createContext,
  useContext,
  type ReactNode,
} from "react";
import type {
  HostContext,
  DesignTokens,
  NotificationBridge,
  TelemetryCallback,
  NavigationBridge,
} from "@weekly-commit/shared";

export interface HostBridge {
  readonly context: HostContext;
  readonly tokens: DesignTokens;
  readonly notifications: NotificationBridge;
  readonly telemetry: TelemetryCallback;
  readonly navigation: NavigationBridge;
}

const HostBridgeContext = createContext<HostBridge | null>(null);

export function useHostBridge(): HostBridge {
  const ctx = useContext(HostBridgeContext);
  if (ctx === null) {
    throw new Error("useHostBridge must be used within a HostProvider");
  }
  return ctx;
}

export function useHostContext(): HostContext {
