// ── Main card ─────────────────────────────────────────────────────────────────

export function ManagerAiSummaryCard({ teamId, weekStart }: ManagerAiSummaryCardProps) {
  const { data, loading, error } = useManagerAiSummary(teamId, weekStart);

  if (loading) {
    return <ManagerAiSummarySkeleton />;
  }

  if (error) {
    return (
      <div
        className="flex items-center gap-2 rounded-default border border-dashed border-border bg-background/60 px-3 py-2.5 text-xs text-muted italic"
        data-testid="manager-ai-summary-error"
      >
        <Bot className="h-3.5 w-3.5 shrink-0" aria-hidden="true" />
        AI team summary unavailable: {error.message}
      </div>
    );
  }

  if (!data || !data.aiAvailable) {
    return (
      <div
        className="flex items-center gap-2 rounded-default border border-dashed border-border bg-background/60 px-3 py-2.5 text-xs text-muted italic"
        data-testid="manager-ai-summary-unavailable"
      >
        <Bot className="h-3.5 w-3.5 shrink-0" aria-hidden="true" />
        AI team summary is currently unavailable.
      </div>
    );
  }

  const hasTopRcdo = data.topRcdoBranches.length > 0;
  const hasCarryForward = data.carryForwardPatterns.length > 0;
  const hasExceptions = data.unresolvedExceptionIds.length > 0;
  const hasCriticalBlocked = data.criticalBlockedItemIds.length > 0;

  return (
    <Card data-testid="manager-ai-summary-card">
      <CardHeader>
        <div className="flex items-center gap-2">
          <Bot className="h-4 w-4 text-primary shrink-0" aria-hidden="true" />
          <span className="text-sm font-semibold text-foreground">AI Team Summary</span>
        </div>
        {data.suggestionId && (
          <AiFeedbackButtons suggestionId={data.suggestionId} />
        )}
      </CardHeader>

      <CardContent className="flex flex-col gap-3">
        {/* Prose summary */}
        {data.summaryText && (
          <p
            className="m-0 text-sm leading-relaxed text-foreground"
            data-testid="manager-ai-summary-text"
          >
            {data.summaryText}
          </p>
        )}

        {/* Top RCDO branches */}
        {hasTopRcdo && (
          <div data-testid="manager-ai-summary-rcdo-branches">
            <p className="m-0 mb-1.5 text-[0.65rem] font-semibold uppercase tracking-wider text-muted">
              Top Strategic Branches
            </p>
            <div className="flex flex-wrap gap-1.5">
              {data.topRcdoBranches.map((branch) => (
                <Badge key={branch} variant="primary" className="text-[0.65rem]">
                  {branch}
                </Badge>
              ))}
            </div>
          </div>
        )}

        {/* Carry-forward patterns */}
        {hasCarryForward && (
          <div data-testid="manager-ai-summary-carry-forward">
            <p className="m-0 mb-1 text-[0.65rem] font-semibold uppercase tracking-wider text-muted flex items-center gap-1">
              <RotateCcw className="h-3 w-3" aria-hidden="true" />
              Carry-Forward Patterns
            </p>
            <ul className="m-0 pl-4 flex flex-col gap-0.5">
              {data.carryForwardPatterns.map((pattern, i) => (
                <li key={i} className="text-xs text-foreground">
                  {pattern}
                </li>
              ))}
            </ul>
          </div>
        )}

        {/* Warnings row: unresolved exceptions + critical blocked items */}
        {(hasExceptions || hasCriticalBlocked) && (
          <div className="flex flex-wrap gap-3 mt-0.5" data-testid="manager-ai-summary-warnings">
            {hasExceptions && (
              <span
                className="flex items-center gap-1.5 text-xs font-semibold text-foreground"
                data-testid="manager-ai-summary-exception-count"
              >
                <AlertTriangle className="h-3.5 w-3.5 shrink-0" aria-hidden="true" />
                {data.unresolvedExceptionIds.length} unresolved exception
                {data.unresolvedExceptionIds.length !== 1 ? "s" : ""}
              </span>
            )}
            {hasCriticalBlocked && (
              <span
                className="flex items-center gap-1.5 text-xs font-semibold text-foreground"
                data-testid="manager-ai-summary-blocked-count"
              >
                <ShieldAlert className="h-3.5 w-3.5 shrink-0" aria-hidden="true" />
                {data.criticalBlockedItemIds.length} critical blocked item
                {data.criticalBlockedItemIds.length !== 1 ? "s" : ""}
              </span>
            )}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

/**
 * ProactiveRiskBanner — displays critical AI-detected risk signals as
 * prominent, persistent banners on the IC's own My Week page.
 *
 * The parent (MyWeek) is responsible for only rendering this component
 * when the plan is LOCKED. Risk signals are filtered to the three critical
 * types that warrant immediate IC attention:
 *   OVERCOMMIT, BLOCKED_CRITICAL, REPEATED_CARRY_FORWARD
 *
 * Non-critical types (UNDERCOMMIT, SCOPE_VOLATILITY) are excluded — they
 * are surfaced on the Team Week risk tab instead.
 */
import { AlertTriangle, ShieldAlert, TrendingDown, RotateCcw } from "lucide-react";
import { cn } from "../../lib/utils.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import { useRiskSignals } from "../../api/aiHooks.js";
import type { RiskSignal } from "../../api/aiApi.js";

// ── Critical signal type filter ───────────────────────────────────────────────

/** Signal types shown as proactive IC banners on My Week. */
const CRITICAL_SIGNAL_TYPES = new Set([
  "OVERCOMMIT",
  "BLOCKED_CRITICAL",
  "REPEATED_CARRY_FORWARD",
]);

// ── Per-type display config ───────────────────────────────────────────────────

interface SignalConfig {
  Icon: typeof AlertTriangle;
  /** Tailwind border + background classes for the banner. */
  cls: string;
  /** Short actionable hint shown below the rationale. */
  actionHint: string;
}

const SIGNAL_CONFIG: Record<string, SignalConfig> = {
  OVERCOMMIT: {
    Icon: TrendingDown,
    cls: "border-neutral-400 bg-neutral-100",
    actionHint: "Consider reducing scope before the week runs out.",
  },
  BLOCKED_CRITICAL: {
    Icon: ShieldAlert,
    cls: "border-neutral-400 bg-neutral-100",
    actionHint: "Resolve the blocked ticket or escalate to your manager.",
  },
  REPEATED_CARRY_FORWARD: {
    Icon: RotateCcw,
    cls: "border-neutral-300 bg-neutral-50",
    actionHint:
      "Review whether this work needs to be broken down or deprioritised.",
  },
};

// ── Individual banner ─────────────────────────────────────────────────────────

function RiskBannerItem({ signal }: { signal: RiskSignal }) {
  const config = SIGNAL_CONFIG[signal.signalType];
  const Icon = config?.Icon ?? AlertTriangle;
  const cls = config?.cls ?? "border-border bg-background";
  const actionHint = config?.actionHint;

  return (
    <div
      className={cn(
        "rounded-default border px-4 py-3 flex items-start gap-3",
        cls,
      )}
      role="alert"
      data-testid={`risk-banner-${signal.id}`}
    >
      <Icon
        className="h-4 w-4 mt-0.5 shrink-0 text-foreground"
        aria-hidden="true"
      />
      <div className="flex-1 min-w-0">
        <div className="flex items-start justify-between gap-2">
          <div className="flex-1 min-w-0">
            <p
              className="m-0 text-sm font-semibold text-foreground"
              data-testid={`risk-banner-type-${signal.id}`}
            >
              {signal.signalType.replace(/_/g, " ")}
            </p>
            <p
              className="m-0 text-sm text-foreground leading-relaxed mt-0.5"
              data-testid={`risk-banner-rationale-${signal.id}`}
            >
              {signal.rationale}
            </p>
            {actionHint && (
              <p
                className="m-0 text-xs text-muted italic mt-1"
                data-testid={`risk-banner-action-${signal.id}`}
              >
                → {actionHint}
              </p>
            )}
          </div>
          {/* signal.id is the AiSuggestion PK — suitable as feedback target */}
          <AiFeedbackButtons suggestionId={signal.id} />
        </div>
      </div>
    </div>
  );
}

// ── Main component ────────────────────────────────────────────────────────────

interface ProactiveRiskBannerProps {
  /** Plan UUID. The parent must only render this for LOCKED plans. */
  planId: string;
}

/**
 * Renders zero or more alert banners for critical AI risk signals.
 * Returns `null` when AI is unavailable, loading, errored, or when no
 * critical signals exist — so callers need no conditional guard.
 */
export function ProactiveRiskBanner({ planId }: ProactiveRiskBannerProps) {
  const { data, loading, error } = useRiskSignals(planId);

  // Keep the UI clean: no loading skeleton for proactive banners.
  if (loading) return null;

  // Silently degrade when AI is unavailable or the fetch failed.
  if (error || !data?.aiAvailable) return null;

  const criticalSignals = data.signals.filter((s) =>
    CRITICAL_SIGNAL_TYPES.has(s.signalType),
  );

  if (criticalSignals.length === 0) return null;

  return (
    <div
      className="flex flex-col gap-2"
      data-testid="proactive-risk-banners"
      aria-label="Active risk signals"
    >
      {criticalSignals.map((signal) => (
        <RiskBannerItem key={signal.id} signal={signal} />
      ))}
    </div>
  );
}

/**
 * ReconcileAssistPanel — "AI Assist Reconciliation" button that pre-fills
 * likely outcomes, generates a draft summary, and suggests carry-forwards.
 *
 * Phase 3b: Wires existing ReconcileAssistService backend to the Reconcile page.
 */
import { useState, useCallback } from "react";
import { Bot, Check, Loader2, RotateCcw, ArrowRight } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Badge } from "../ui/Badge.js";
import { Card, CardContent, CardHeader, CardTitle } from "../ui/Card.js";
import { cn } from "../../lib/utils.js";
import { useAiApi, useAiStatus } from "../../api/aiHooks.js";
import { useHostBridge } from "../../host/HostProvider.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import type {
  ReconcileAssistResponse,
  CommitOutcomeSuggestion,
  CarryForwardRecommendation,
} from "../../api/aiApi.js";
import type { CommitOutcome } from "../../api/planTypes.js";

const OUTCOME_COLORS: Record<string, string> = {
  ACHIEVED: "bg-foreground/10 text-foreground font-bold",
  PARTIALLY_ACHIEVED: "bg-neutral-200 text-neutral-600",
  NOT_ACHIEVED: "bg-neutral-300 text-foreground underline",
  CANCELED: "bg-neutral-100 text-neutral-500",
};

const OUTCOME_LABELS: Record<string, string> = {
  ACHIEVED: "Achieved",
  PARTIALLY_ACHIEVED: "Partial",
  NOT_ACHIEVED: "Not Achieved",
  CANCELED: "Canceled",
};

interface ReconcileAssistPanelProps {
  planId: string;
  /** Callback when the user accepts an outcome suggestion. */
  onAcceptOutcome?: ((commitId: string, outcome: CommitOutcome) => void) | undefined;
  /** Callback when the user accepts a carry-forward recommendation. */
  onAcceptCarryForward?: ((commitId: string) => void) | undefined;
  className?: string | undefined;
}

export function ReconcileAssistPanel({
  planId,
  onAcceptOutcome,
  onAcceptCarryForward,
  className,
}: ReconcileAssistPanelProps) {
  const aiApi = useAiApi();
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;
  const { data: aiStatus } = useAiStatus();
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ReconcileAssistResponse | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [appliedOutcomes, setAppliedOutcomes] = useState<Set<string>>(new Set());
  const [appliedCarryForwards, setAppliedCarryForwards] = useState<Set<string>>(new Set());

  const isAvailable = aiStatus?.available ?? false;

  const handleRequest = useCallback(async () => {
    setLoading(true);
    setError(null);
    setResult(null);
    setAppliedOutcomes(new Set());
    setAppliedCarryForwards(new Set());
    try {
      const response = await aiApi.reconcileAssist({ planId, userId });
      if (!response.aiAvailable) {
        setError("AI is currently unavailable.");
        return;
      }
      setResult(response);
    } catch {
      setError("Failed to get reconciliation suggestions.");
    } finally {
      setLoading(false);
    }
  }, [aiApi, planId, userId]);

  const handleApplyOutcome = useCallback(
    (suggestion: CommitOutcomeSuggestion) => {
      onAcceptOutcome?.(suggestion.commitId, suggestion.suggestedOutcome as CommitOutcome);
      setAppliedOutcomes((prev) => new Set(prev).add(suggestion.commitId));
    },
    [onAcceptOutcome],
  );

  const handleApplyCarryForward = useCallback(
    (rec: CarryForwardRecommendation) => {
      onAcceptCarryForward?.(rec.commitId);
      setAppliedCarryForwards((prev) => new Set(prev).add(rec.commitId));
    },
    [onAcceptCarryForward],
  );

  // Not yet requested
  if (!result && !loading && !error) {
    return (
      <div className={cn("flex items-center gap-2", className)}>
        <Button
          variant="ghost"
          size="sm"
          onClick={() => void handleRequest()}
          disabled={!isAvailable}
          className="text-primary hover:text-primary/80 border border-dashed border-primary/30"
          data-testid="reconcile-assist-btn"
          title={!isAvailable ? "AI unavailable" : "Get AI suggestions for reconciliation"}
        >
          <Bot className="h-3.5 w-3.5 mr-1.5" />
          AI Assist Reconciliation
        </Button>
      </div>
    );
  }

  // Loading
  if (loading) {
    return (
      <div
        className={cn("flex items-center gap-2 text-sm text-muted animate-pulse", className)}
        data-testid="reconcile-assist-loading"
      >
        <Loader2 className="h-4 w-4 animate-spin" />
        Analyzing your week…
      </div>
    );
  }

  // Error
  if (error) {
    return (
      <div
        className={cn(
          "flex items-center justify-between gap-2 rounded-default border border-danger/30 bg-danger/5 px-3 py-2",
          className,
        )}
        data-testid="reconcile-assist-error"
      >
        <span className="text-xs text-danger">{error}</span>
        <Button
          variant="ghost"
          size="sm"
          onClick={() => void handleRequest()}
          className="h-6 text-xs"
          data-testid="reconcile-assist-retry"
        >
          <RotateCcw className="h-3 w-3 mr-1" />
          Retry
        </Button>
      </div>
    );
  }

  if (!result) return null;

  const hasOutcomes = result.likelyOutcomes.length > 0;
  const hasCarryForwards = result.carryForwardRecommendations.length > 0;
  const hasSummary = result.draftSummary && result.draftSummary.trim().length > 0;

  return (
    <Card className={cn("w-full", className)} data-testid="reconcile-assist-panel">
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-sm">
          <Bot className="h-4 w-4 text-primary" />
          AI Reconciliation Suggestions
        </CardTitle>
        <div className="flex items-center gap-2">
          {result.suggestionId && (
            <AiFeedbackButtons suggestionId={result.suggestionId} />
          )}
          <Button
            variant="ghost"
            size="sm"
            onClick={() => void handleRequest()}
            className="h-6 text-xs"
            data-testid="reconcile-assist-refresh"
          >
            <RotateCcw className="h-3 w-3" />
          </Button>
        </div>
      </CardHeader>

      <CardContent className="flex flex-col gap-4">
        {/* Draft summary */}
        {hasSummary && (
          <div data-testid="reconcile-assist-summary">
            <p className="m-0 mb-1 text-xs font-semibold text-muted uppercase tracking-wider">
              Week Summary
            </p>
            <p className="m-0 text-sm leading-relaxed text-foreground bg-background rounded-default px-3 py-2 border border-border">
              {result.draftSummary}
            </p>
          </div>
        )}

        {/* Outcome suggestions */}
        {hasOutcomes && (
          <div data-testid="reconcile-assist-outcomes">
            <p className="m-0 mb-2 text-xs font-semibold text-muted uppercase tracking-wider">
              Suggested Outcomes
            </p>
            <div className="flex flex-col gap-1.5">
              {result.likelyOutcomes.map((suggestion) => {
                const isApplied = appliedOutcomes.has(suggestion.commitId);
                const colorCls =
                  OUTCOME_COLORS[suggestion.suggestedOutcome] ?? "bg-neutral-100 text-neutral-700";
                return (
                  <div
                    key={suggestion.commitId}
                    className={cn(
                      "flex items-start gap-2 rounded-sm border px-2.5 py-2 text-xs",
                      isApplied ? "border-foreground/20 bg-foreground/5" : "border-border",
                    )}
                    data-testid={`outcome-suggestion-${suggestion.commitId}`}
                  >
                    <div className="flex-1 min-w-0">
                      <span className="font-semibold">{suggestion.commitTitle}</span>
                      <div className="flex items-center gap-1.5 mt-1">
                        <Badge
                          variant="default"
                          className={cn("text-[0.6rem]", colorCls)}
                        >
                          {OUTCOME_LABELS[suggestion.suggestedOutcome] ??
                            suggestion.suggestedOutcome}
                        </Badge>
                        <span className="text-muted">{suggestion.rationale}</span>
                      </div>
                    </div>
                    {!isApplied && onAcceptOutcome && (
                      <Button
                        type="button"
                        variant="ghost"
                        size="icon"
                        onClick={() => handleApplyOutcome(suggestion)}
                        className="h-6 w-6 text-primary hover:bg-primary/10 shrink-0"
                        aria-label={`Apply ${suggestion.suggestedOutcome} to ${suggestion.commitTitle}`}
                        data-testid={`apply-outcome-${suggestion.commitId}`}
                      >
                        <Check className="h-3.5 w-3.5" />
                      </Button>
                    )}
                    {isApplied && (
                      <span className="text-[0.6rem] text-foreground font-semibold shrink-0">
                        ✓ Applied
                      </span>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* Carry-forward recommendations */}
        {hasCarryForwards && (
          <div data-testid="reconcile-assist-carry-forwards">
            <p className="m-0 mb-2 text-xs font-semibold text-muted uppercase tracking-wider">
              Carry Forward Recommendations
            </p>
            <div className="flex flex-col gap-1.5">
              {result.carryForwardRecommendations.map((rec) => {
                const isApplied = appliedCarryForwards.has(rec.commitId);
                return (
                  <div
                    key={rec.commitId}
                    className={cn(
                      "flex items-start gap-2 rounded-sm border px-2.5 py-2 text-xs",
                      isApplied
                        ? "border-foreground/15 bg-foreground/[0.03]"
                        : "border-border",
                    )}
                    data-testid={`carry-forward-rec-${rec.commitId}`}
                  >
                    <ArrowRight className="h-3.5 w-3.5 mt-0.5 text-muted shrink-0" />
                    <div className="flex-1 min-w-0">
                      <span className="font-semibold">{rec.commitTitle}</span>
                      <p className="m-0 mt-0.5 text-muted">{rec.rationale}</p>
                    </div>
                    {!isApplied && onAcceptCarryForward && (
                      <Button
                        type="button"
                        variant="ghost"
                        size="sm"
                        onClick={() => handleApplyCarryForward(rec)}
                        className="h-6 text-xs text-foreground hover:bg-neutral-100 shrink-0"
                        aria-label={`Carry forward ${rec.commitTitle}`}
                        data-testid={`apply-carry-forward-${rec.commitId}`}
                      >
                        🔁 Carry Forward
                      </Button>
                    )}
                    {isApplied && (
                      <span className="text-[0.6rem] text-foreground font-semibold shrink-0">
                        ✓ Queued
                      </span>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {!hasOutcomes && !hasCarryForwards && !hasSummary && (
          <p className="text-xs text-muted italic" data-testid="reconcile-assist-empty">
            No additional suggestions — your reconciliation looks straightforward.
          </p>
        )}
      </CardContent>
    </Card>
  );
}

/**
 * RcdoSuggestionInline — shows an AI-suggested RCDO link below the RCDO picker
 * in CommitForm. Fires the existing `/api/ai/rcdo-suggest` endpoint when the
 * user has typed enough title text, and presents the suggestion with rationale
 * + confidence + accept/dismiss controls.
 *
 * PRD §17: assistive, visible rationale, auditable, never auto-links.
 */
import { useState, useEffect, useRef, useCallback } from "react";
import { Check, X, Loader2 } from "lucide-react";
import { Button } from "../ui/Button.js";
import { cn } from "../../lib/utils.js";
import { useAiApi, useAiStatus } from "../../api/aiHooks.js";
import { useHostBridge } from "../../host/HostProvider.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import { AiSuggestedBadge } from "./AiSuggestedBadge.js";
import type { RcdoSuggestResponse } from "../../api/aiApi.js";

interface RcdoSuggestionInlineProps {
  planId: string;
  /** Current commit title — used for semantic matching. */
  currentTitle: string;
  /** Current commit description (optional extra context). */
  currentDescription?: string | undefined;
  /** Current chess piece (optional extra context). */
  chessPiece?: string | undefined;
  /** Currently selected RCDO node id (skip suggestion if already set). */
  currentRcdoNodeId: string;
  /** Called when user accepts the suggestion. */
  onAccept: (rcdoNodeId: string) => void;
  className?: string | undefined;
}

const MIN_TITLE_LENGTH = 8;
const DEBOUNCE_MS = 1200;

export function RcdoSuggestionInline({
  planId,
  currentTitle,
  currentDescription,
  chessPiece,
  currentRcdoNodeId,
  onAccept,
  className,
}: RcdoSuggestionInlineProps) {
  const aiApi = useAiApi();
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;
  const { data: aiStatus } = useAiStatus();

  const [result, setResult] = useState<RcdoSuggestResponse | null>(null);
  const [loading, setLoading] = useState(false);
  const [dismissed, setDismissed] = useState(false);
  const [accepted, setAccepted] = useState(false);

  const isAvailable = aiStatus?.available ?? false;

  // Debounce timer ref
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  // Track what we last fetched for to avoid duplicate requests
  const lastFetchedRef = useRef<string>("");

  // Reset dismissed/accepted state when the title meaningfully changes
  const titleKeyRef = useRef(currentTitle);
  useEffect(() => {
    if (currentTitle !== titleKeyRef.current) {
      titleKeyRef.current = currentTitle;
      setDismissed(false);
      setAccepted(false);
    }
  }, [currentTitle]);

  // Debounced fetch
  useEffect(() => {
    // Don't suggest if AI unavailable, title too short, user already picked an RCDO,
    // or we've been dismissed
    if (
      !isAvailable ||
      currentTitle.trim().length < MIN_TITLE_LENGTH ||
      currentRcdoNodeId ||
      dismissed
    ) {
      return;
    }

    const key = `${currentTitle.trim()}|${chessPiece ?? ""}`;
    if (key === lastFetchedRef.current) return;

    if (timerRef.current) clearTimeout(timerRef.current);

    timerRef.current = setTimeout(() => {
      lastFetchedRef.current = key;
      setLoading(true);
      aiApi
        .rcdoSuggest({
          planId,
          userId,
          title: currentTitle.trim(),
          description: currentDescription,
          chessPiece,
        })
        .then((response) => {
          setResult(response);
          setLoading(false);
        })
        .catch(() => {
          setResult(null);
          setLoading(false);
        });
    }, DEBOUNCE_MS);

    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentTitle, currentRcdoNodeId, dismissed, isAvailable, chessPiece]);

  const handleAccept = useCallback(() => {
    if (!result?.suggestedRcdoNodeId) return;
    onAccept(result.suggestedRcdoNodeId);
    setAccepted(true);
  }, [result, onAccept]);

  const handleDismiss = useCallback(() => {
    setDismissed(true);
    setResult(null);
  }, []);

  // Don't render anything if AI is unavailable, nothing to show, or user already
  // has an RCDO selected
  if (!isAvailable || currentRcdoNodeId || dismissed || accepted) return null;

  if (loading) {
    return (
      <div
        className={cn("flex items-center gap-2 text-xs text-muted animate-pulse mt-1.5", className)}
        data-testid="rcdo-suggestion-loading"
      >
        <Loader2 className="h-3 w-3 animate-spin" />
        Finding best RCDO match…
      </div>
    );
  }

  if (!result?.aiAvailable || !result?.suggestionAvailable || !result?.suggestedRcdoNodeId) {
    return null;
  }

  return (
    <div
      className={cn(
        "flex items-start gap-2 rounded-default border border-primary/20 bg-primary/5 px-3 py-2 mt-1.5",
        className,
      )}
      data-testid="rcdo-suggestion-inline"
    >
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-1.5 flex-wrap">
          <AiSuggestedBadge />
          <span className="text-sm font-semibold text-foreground" data-testid="rcdo-suggestion-title">
            {result.rcdoTitle ?? result.suggestedRcdoNodeId.slice(0, 8) + "…"}
          </span>
          {result.confidence != null && (
            <span className="text-[0.65rem] text-muted" data-testid="rcdo-suggestion-confidence">
              {Math.round(result.confidence * 100)}%
            </span>
          )}
        </div>
        {result.rationale && (
          <p className="m-0 mt-0.5 text-xs text-muted" data-testid="rcdo-suggestion-rationale">
            {result.rationale}
          </p>
        )}
      </div>
      <div className="flex items-center gap-1 shrink-0">
        {result.suggestionId && <AiFeedbackButtons suggestionId={result.suggestionId} />}
        <Button
          variant="ghost"
